module RefModule (s, cout, a, b, cin);
   input [3:0] a, b;
   input cin;
   output [3:0] s;
   output cout;

   wire [3:0] obf_g; // Generate
   wire [3:0] p; // Propagate
   wire [4:0] c; // Carry

   assign obf_g = a & b;
   assign p = a ^ b;

   assign c[0] = cin;
   assign c[1] = obf_g[0] | (p[0] & c[0]);
   assign c[2] = obf_g[1] | (p[1] & c[1]);
   assign c[3] = obf_g[2] | (p[2] & c[2]);
   assign c[4] = obf_g[3] | (p[3] & c[3]);

   assign s = p ^ c[3:0];
   assign cout = c[4];

endmodule
